{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}}
                    {\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
                    \widowctrl\hyphauto
{\pard \ql \f0 \sa180 \li0 \fi0 Simple JSFX that allows you to use your MIDI Expression pedal to control Hi-hat open level in multisampled drums.\par}
                }

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}}
                    {\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
                    \widowctrl\hyphauto
{\pard \ql \f0 \sa180 \li0 \fi0 Simple JSFX that allows you to use your Sustain pedal as a kick drum.\par}
                }

{\rtf1\ansi\deff0{\fonttbl{\f0 \fswiss Helvetica;}}
                    {\colortbl;\red255\green0\blue0;\red0\green0\blue255;}
                    \widowctrl\hyphauto

{\pard \ql \f0 \sa180 \li0 \fi0 \b \fs36 DrumKey\par}
{\pard \ql \f0 \sa180 \li0 \fi0 Play your MIDI Keyboard (+ Sustain Pedal) like it was an e-drum set.\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Use your Sustain pedal to output fixed velocity kick drum notes\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Use the Mod wheel for Hi-hat open-ness\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 \bullet \tx360\tab Duplicate input keys for Snare and Toms for easier fills\sa180\par}
                }

